'use strict';

const S = require('./item_content.cjs').sources;
const section = (heading, content, keyTerms) => ({ heading, content, keyTerms });
const chapter = (id, skillId, title, summary, objectives, sections, flashcards) => ({ id, skillId, title, summary, objectives, sections, flashcards });

const chapters = [
  chapter('sp5403-ch-01', 'problem-solving-data-integration', 'Problem Solving and Multimethod Data Integration',
    'Use a RIOT-informed problem-solving cycle to define concerns, analyze alterable causes, select interventions, monitor response and fidelity, and communicate integrated conclusions.',
    ['Operationalize referral concerns and select relevant sources.', 'Link hypotheses to interventions and progress measures.', 'Integrate evidence into actionable reports and decisions.'], [
      section('From referral label to measurable problem', 'Begin by replacing labels such as unmotivated, defiant, or low ability with an observable discrepancy between current and expected performance. Specify behavior or skill, setting, task, frequency or accuracy, duration, relevant comparison, baseline, and student-valued outcome. Review developmental, instructional, attendance, language, health, sensory, intervention, and family history only because it can clarify the question. A precise definition prevents assessment from becoming a routine battery searching for a problem.', ['problem identification', 'baseline', 'referral question']),
      section('RIOT and ecological hypothesis testing', 'RIOT organizes records, interviews, observations, and tests or other direct measures. Select sources that can confirm the concern, reveal contexts and exceptions, identify strengths, and distinguish skill, performance, instructional, language, health, and environmental contributors. Disagreement across sources is information: compare setting, task, informant, timing, opportunity, and measure quality. Form testable hypotheses about alterable variables instead of treating a disability label or trait judgment as an explanation.', ['RIOT', 'ecological assessment', 'testable hypothesis']),
      section('Intervention, monitoring, and fidelity', 'Match intervention mechanism to the hypothesis. Missing skills call for explicit instruction and practice; inconsistent performance may require antecedent changes, efficient prompts, motivation, or reinforcement; escape-maintained behavior requires task and replacement-skill changes. Use a sensitive, repeatable aligned measure, a goal line, and a prespecified decision rule. Collect adherence, dosage, quality, and access data so weak outcomes can be distinguished from incomplete implementation.', ['intervention match', 'progress monitoring', 'treatment integrity']),
      section('Integration and communication', 'Integrate patterns rather than listing sources in isolation. Answer each referral question, describe strengths and needs, explain convergence and discrepancy, state uncertainty and limitations, and connect findings to feasible supports and outcome measures. Reports and meetings should use accessible language, labeled visuals, respectful person-centered descriptions, and opportunities for student and family questions. A score is useful only through a defensible interpretation tied to educational action.', ['data integration', 'psychoeducational report', 'uncertainty']),
    ], [['What does RIOT stand for?', 'Review records, Interview, Observe, and Test or otherwise directly measure as appropriate.'], ['What makes a problem definition useful?', 'Observable performance, context, baseline, expected level, and a meaningful measurable goal.'], ['How should conflicting sources be handled?', 'Compare context, task, informant, timing, opportunity, and measure quality rather than averaging them away.'], ['What links assessment to intervention?', 'A testable hypothesis about an alterable cause and a strategy matched to that mechanism.'], ['Why collect fidelity?', 'To determine whether weak outcomes reflect the intervention theory or incomplete delivery.'], ['What makes an integrated report actionable?', 'It answers referral questions, explains uncertainty, and links strengths and needs to feasible supports and measures.']]),

  chapter('sp5403-ch-02', 'measurement-assessment-special-populations', 'Measurement and Assessment of Diverse Learners',
    'Interpret reliability, validity, score uncertainty, norms, and multiple assessment methods while preserving construct access and nondiscriminatory practice.',
    ['Explain score precision and validity for a specific use.', 'Select academic, cognitive, behavioral, adaptive, and developmental methods appropriately.', 'Plan culturally, linguistically, and disability-responsive assessment.'], [
      section('Reliability, error, and score precision', 'Reliability concerns consistency or precision under relevant conditions. Standard error of measurement and confidence intervals express expected imprecision around an obtained score; they discourage rank-ordering students on trivial differences. Reliability can vary by score, population, task, and purpose. Interrater agreement matters for observations and ratings, internal consistency for item sets, and alternate-form or test-retest evidence for repeated decisions. No reliability coefficient makes a measure valid for every inference.', ['reliability', 'standard error of measurement', 'confidence interval']),
      section('Validity, constructs, and norms', 'Validity is the evidence and reasoning supporting a specific interpretation and use for a population and context. Ask what construct is intended, what irrelevant skills may affect performance, whether content and response processes fit, how scores relate to relevant outcomes, and what consequences follow. Percentile ranks show relative standing in a named norm group and are not percent correct. Standard scores, age or grade norms, and classifications require relevant contemporary comparisons and honest uncertainty.', ['validity', 'construct', 'percentile rank']),
      section('A purpose-driven assessment toolbox', 'Cognitive, achievement, processing, curriculum-based, performance, rating, interview, observation, self-report, adaptive, and developmental methods answer different questions. Cognitive tests do not become automatic gates to services; CBM is well suited to repeated academic monitoring; self-report can reveal private experience but needs developmental and response-style review; adaptive ratings describe typical everyday functioning across contexts. Select the least burdensome sources capable of answering the decision and integrate them.', ['curriculum-based measurement', 'self-report', 'adaptive functioning']),
      section('Language, culture, disability, and access', 'Distinguish difference from disability by examining language proficiency across languages, instruction and opportunity, mobility, acculturation, family evidence, and intervention response. Use qualified interpreters and measures or procedures in the form most likely to yield accurate information. For sensory, motor, communication, or health needs, remove construct-irrelevant barriers while preserving the target; document accommodations, departures from standardization, and limits on score interpretation.', ['nondiscriminatory assessment', 'language proficiency', 'construct-irrelevant variance']),
    ], [['What is reliability?', 'The consistency or precision of scores under relevant conditions.'], ['What does SEM support?', 'A confidence interval or plausible score range rather than false precision from one observed score.'], ['What is validity?', 'Evidence and reasoning supporting a specific interpretation and use for a population and context.'], ['What does percentile rank mean?', 'The percentage of a relevant norm group scoring at or below the obtained score.'], ['When is CBM especially useful?', 'For brief repeatable measurement of academic level and growth aligned to an instructional target.'], ['What is the access principle in assessment?', 'Remove irrelevant barriers while preserving the construct and documenting interpretive limits.']]),

  chapter('sp5403-ch-03', 'consultation-collaboration', 'Consultation and Collaborative Problem Solving',
    'Build shared ownership through clear goals, respectful communication, feasible plans, role clarity, language access, and outcome-focused follow-up.',
    ['Apply a structured consultation cycle.', 'Resolve disagreement through evidence and common goals.', 'Coordinate families, educators, and community partners within privacy boundaries.'], [
      section('A consultation cycle', 'Establish a collaborative relationship, clarify roles, operationalize the concern, review context and strengths, set a shared measurable goal, analyze causes, select a feasible evidence-informed plan, define responsibilities, implement with support, and review fidelity and outcomes. Consultation develops another person’s capacity rather than transferring the classroom, family, or service role to the psychologist. The meeting itself is participation, not evidence that the concern improved.', ['consultation', 'shared goal', 'role clarity']),
      section('Feasibility, acceptability, and implementation', 'A theoretically strong intervention can fail when it does not fit routines, resources, culture, skill, or workload. Ask what will make the plan usable, distinguish core mechanism from adaptable features, model and rehearse procedures, provide materials and feedback, and create a light fidelity check. If a consultee hesitates, explore the barrier rather than labeling resistance. Adapt collaboratively and document which version is being tested.', ['acceptability', 'feasibility', 'adaptation']),
      section('Communication across difference and disagreement', 'Use plain language, visuals, teach-back, active listening, and interpreters or translated material as needed. Treat conflicting home and school reports as ecological evidence rather than selecting a winner. During team conflict, return to the student-valued outcome, make assumptions explicit, identify common evidence and uncertainty, compare harms and feasibility, and select a reversible test with a review date. Power and professional jargon should not substitute for reasoning.', ['language access', 'team conflict', 'teach-back']),
      section('Community coordination and consultation outcomes', 'Outside providers can contribute when purpose, consent, roles, secure information sharing, school responsibilities, and follow-up are clear. Share only authorized necessary information. Evaluate consultation through implementation, student outcomes, feasibility, satisfaction, capacity growth, and unintended effects. A supported referral addresses fit, cost, transportation, language, availability, and continuity instead of ending school support after a phone number is given.', ['interagency collaboration', 'supported referral', 'consultation evaluation']),
    ], [['What begins consultation?', 'A collaborative relationship and an observable shared definition of the concern and desired change.'], ['Who retains classroom responsibility?', 'The teacher, while psychologist and teacher share planning, support, and review within their roles.'], ['Why assess acceptability?', 'A plan that stakeholders cannot or will not use is unlikely to be implemented well.'], ['How should disagreement be handled?', 'Return to shared goals and evidence, expose assumptions, test a feasible option, and schedule review.'], ['What protects outside-provider coordination?', 'Clear purpose, consent, role boundaries, necessary secure disclosure, and follow-up.'], ['How is consultation evaluated?', 'Through fidelity, meaningful outcomes, feasibility, stakeholder experience, and capacity—not meeting count alone.']]),

  chapter('sp5403-ch-04', 'academic-instructional-interventions', 'Academic Interventions and Instructional Supports',
    'Match explicit and differentiated instruction, access supports, self-regulation, and progress monitoring to specific academic skills and contextual barriers.',
    ['Design explicit instruction from error analysis.', 'Distinguish accommodation from modification.', 'Set measurable goals and promote self-regulated learning.'], [
      section('Instruction follows error analysis', 'An overall low score does not specify whether the learner lacks a concept, strategy, prerequisite, fluency, language access, or sufficient practice. Examine correct and incorrect responses, task conditions, instructional history, and opportunity. Explicit instruction models the target and thinking, prompts many accurate responses, gives immediate specific feedback, checks understanding, uses cumulative review, and releases responsibility when data show readiness rather than after a fixed number of lessons.', ['error analysis', 'explicit instruction', 'guided practice']),
      section('Differentiation, accommodation, and modification', 'Differentiation varies examples, scaffolds, grouping, pacing, representation, and response options while pursuing a coherent core goal. An accommodation removes a barrier unrelated to the target without changing what is taught or measured. A modification changes content, complexity, or expected performance and must be decided and documented appropriately. Assistive technology should be selected through task-barrier analysis, authentic trials, training, usability, independence, and outcome evidence.', ['differentiation', 'accommodation', 'modification']),
      section('Goals and self-regulation', 'A measurable academic goal names conditions, observable performance, baseline, criterion or magnitude, timeframe, and measurement method. Student ownership grows when learners set proximal goals, select and use strategies, self-monitor accurately, compare results with criteria, and adjust. Model each routine, provide feedback, and fade adult prompts deliberately. Independence is an outcome to measure; permanent close prompting can hide skill and create dependence.', ['measurable goal', 'self-monitoring', 'prompt fading']),
      section('Evidence-based selection and progress decisions', 'Integrate credible intervention research with the specific skill, learner characteristics, language and culture, setting, resources, and implementation capacity. Monitor using repeatable measures sensitive to the target and graph level, trend, variability, and goal. Apply an advance decision rule only after checking fidelity and access. Continue when response is adequate, adapt the mechanism when error patterns change, intensify when growth is insufficient, and reconsider the hypothesis when implementation was strong but outcomes remain weak.', ['evidence-based practice', 'goal line', 'decision rule']),
    ], [['What does error analysis identify?', 'The specific misconception, strategy, prerequisite, or task condition hidden by a total score.'], ['What defines explicit instruction?', 'Modeling, guided responding, immediate feedback, cumulative review, and data-based gradual release.'], ['Accommodation versus modification?', 'Accommodation preserves the target; modification changes the content, complexity, or expected performance.'], ['What makes a goal measurable?', 'Condition, observable behavior, baseline, criterion, timeframe, and measurement method.'], ['What builds self-regulation?', 'Goal setting, strategy use, self-monitoring, self-evaluation, feedback, and prompt fading.'], ['What should precede intensification?', 'Review of trend, error patterns, fidelity, dosage, access, and intervention match.']]),

  chapter('sp5403-ch-05', 'mental-behavioral-health', 'Mental and Behavioral Health Services',
    'Provide tiered prevention and developmentally responsive supports using risk and protective factors, trauma-informed practice, brief counseling, and outcome evidence.',
    ['Differentiate primary, secondary, and tertiary supports.', 'Apply trauma-informed and theory-linked interventions.', 'Recognize concern patterns without diagnosing from signs alone.'], [
      section('A continuum from promotion to intensive care', 'Primary or Tier 1 services build protective skills and safe environments for broad populations. Secondary or Tier 2 supports target students with shared elevated need. Tertiary or Tier 3 services are intensive and individualized and may include coordinated community treatment. Tiers describe support, not identity. Use screening and referral only when follow-up capacity, consent or notice requirements, culturally responsive procedures, and clear crisis pathways are in place.', ['primary prevention', 'secondary intervention', 'tertiary intervention']),
      section('Risk, protection, and trauma-informed care', 'Assess biological, developmental, family, peer, school, community, cultural, and historical influences without treating risk as destiny. Protective relationships, belonging, coping, problem solving, safe predictable routines, identity affirmation, and service access can be strengthened. Trauma-informed practice emphasizes physical and emotional safety, choice, voice, regulation, connection, and avoidance of coercive disclosure or deficit assumptions; it is a service framework, not a diagnosis.', ['risk factor', 'protective factor', 'trauma-informed']),
      section('Counseling theories as mechanisms', 'Person-centered conditions include empathy, genuineness, and nonjudgmental regard. CBT connects thoughts, feelings, physiology, and behavior through reappraisal and practice. Solution-focused work identifies preferred outcomes, exceptions, strengths, scaling, and small next steps. Applied behavioral methods change antecedents, teach skills, and arrange consequences based on function. Adapt language, activity, autonomy, and family involvement to development and culture while preserving safety and the agreed goal.', ['person-centered', 'cognitive behavioral', 'solution-focused']),
      section('Concern recognition, referral, and evaluation', 'Withdrawal, irritability, loss of interest, worry, somatic complaints, inattention, aggression, or mood change may signal several mental-health, medical, developmental, contextual, or environmental concerns. Assess safety and educational functioning, collect multi-source evidence, avoid diagnosing from a checklist, and connect the student with qualified evaluation or care. Evaluate school interventions with baseline, repeated outcomes, fidelity, participation, student experience, equity, adverse effects, generalization, and maintenance.', ['differential hypothesis', 'safety assessment', 'maintenance']),
    ], [['What is primary prevention?', 'Universal promotion or prevention intended for the broad population before severe need emerges.'], ['What does a tier describe?', 'The intensity of support, not a permanent type of student.'], ['What is trauma-informed practice?', 'Safety, predictability, voice, choice, regulation, connection, cultural responsiveness, and no forced disclosure.'], ['What does CBT connect?', 'Thoughts, emotion, physiology, and behavior through collaborative reappraisal and practice.'], ['Why avoid diagnosing from warning signs alone?', 'Similar signs can reflect multiple developmental, medical, contextual, and mental-health explanations.'], ['How should a group intervention be evaluated?', 'With outcomes, fidelity, reach, experience, equity, adverse effects, generalization, and maintenance.']]),

  chapter('sp5403-ch-06', 'behavior-counseling-crisis', 'Behavior Analysis, Counseling, and Student Crisis Response',
    'Use observable definitions and functional assessment to design replacement-skill plans, deliver active counseling supports, and respond immediately to student safety concerns.',
    ['Conduct a functional behavior assessment.', 'Design prevention, teaching, and reinforcement around function.', 'Apply safety-first crisis and supported-referral procedures.'], [
      section('Operational definition and ABC evidence', 'Define behavior through visible actions with examples, nonexamples, and a unit such as frequency, rate, duration, latency, or interval. Gather antecedent-behavior-consequence information across occurrences and nonoccurrences, settings, tasks, people, and time. Interviews and rating scales generate hypotheses; direct observation tests them. A disability label, emotion, or moral judgment is not a function. Common consequences may involve attention, escape, tangibles, or automatic effects, but function must be demonstrated.', ['operational definition', 'ABC data', 'behavior function']),
      section('Function-matched intervention', 'A useful plan prevents predictable triggers, changes instruction or environment, teaches an efficient acceptable response serving the same function, reinforces that response, avoids inadvertently strengthening problem behavior, and monitors outcomes and fidelity. Escape-maintained disruption may require task adjustment and help or break requests; attention-maintained behavior may require planned attention for an appropriate bid. Punishment alone does not teach the needed skill or correct the setting event.', ['replacement behavior', 'antecedent strategy', 'reinforcement']),
      section('Counseling groups and generalization', 'Screen students for shared need, readiness, safety, developmental fit, and whether another service is needed. Explain purpose, participation conditions, records, counselor privacy limits, and inability to guarantee peer confidentiality. Teach skills explicitly with modeling, rehearsal, feedback, and practice in real settings. Coordinate with educators and families as authorized, collect student-centered outcomes, and plan maintenance and generalization rather than assuming group-room performance will transfer.', ['group screening', 'confidentiality limits', 'generalization']),
      section('Immediate risk and continuity', 'For a specific imminent suicide, self-harm, or violence concern, maintain appropriate supervision, activate the current school crisis and threat procedures, involve required caregivers or emergency supports, reduce access to means when within role, document, and ensure follow-up. Never promise secrecy. When need exceeds school scope or competence, make a supported referral that addresses consent, resource fit, transportation, language, cost, connection, and continued school-based support.', ['imminent risk', 'crisis protocol', 'continuity of care']),
    ], [['What makes a behavior definition observable?', 'Independent observers can identify examples and nonexamples and measure the same response.'], ['What does an FBA test?', 'Relations among setting, antecedents, behavior, consequences, and likely function.'], ['What is a replacement behavior?', 'An acceptable, efficient response that obtains the same needed outcome or support.'], ['How is reinforcement defined?', 'A consequence relation that increases the future frequency of behavior.'], ['Can group confidentiality be guaranteed?', 'No. The psychologist protects privacy and teaches norms but cannot control peers.'], ['What comes first with imminent suicide risk?', 'Maintain supervision and activate current protective procedures and required supports immediately.']]),

  chapter('sp5403-ch-07', 'schoolwide-learning-mtss', 'Schoolwide Learning, MTSS, and Systems Change',
    'Use needs assessment, integrated MTSS, equitable screening, implementation supports, and program evaluation to improve learning and behavior at scale.',
    ['Build system priorities from disaggregated need and resources.', 'Evaluate screening and policy decisions.', 'Support implementation, equity, and scale.'], [
      section('Needs, assets, and resource mapping', 'Define a system concern with disaggregated achievement, attendance, behavior, climate, screening, and access data. Add student, family, staff, and community perspectives and map existing programs, personnel, schedules, partnerships, funding, and gaps. A needs assessment should identify who experiences the problem, where and when, likely contributors, current strengths, and the capacity to respond. Purchasing a popular program before this work risks solving the wrong problem.', ['needs assessment', 'resource mapping', 'system baseline']),
      section('Integrated MTSS', 'An effective MTSS aligns academic, behavioral, and social-emotional promotion, screening, tiered evidence-informed support, progress monitoring, fidelity, data teams, and problem solving. Universal services continue while students receive targeted or intensive help; tiers are not placements or eligibility categories. Decision rules should trigger timely support, not waiting for severe failure, and MTSS must not delay an evaluation required under law. Integration reduces duplicate teams and conflicting plans.', ['MTSS', 'universal support', 'data team']),
      section('Screening and policy evaluation', 'A screener needs evidence for the intended use, representative participation, equitable access, clear decision rules, manageable false-positive and false-negative consequences, and follow-up capacity. Evaluate policies such as retention, tracking, discipline, testing, and promotion using credible research and local subgroup outcomes, opportunity, burden, and unintended effects. Tradition and schoolwide averages do not establish effectiveness or fairness.', ['universal screening', 'false positive', 'policy evaluation']),
      section('Implementation, scale, and equity', 'Identify core components and adaptable features, then provide leadership, training, coaching, materials, protected time, data systems, and rapid feedback. Monitor adherence, dosage, quality, reach, responsiveness, adaptations, burden, and outcomes. When aggregate results improve but a subgroup gap grows, examine referral and decision points, access, definitions, bias, and affected voices. Scale only after demonstrating feasible implementation and meaningful equitable benefit.', ['implementation science', 'core component', 'disaggregated outcome']),
    ], [['What belongs in a needs assessment?', 'Disaggregated outcomes, stakeholder voice, context, current practices, resources, access, and capacity.'], ['What makes MTSS integrated?', 'Common problem solving, screening, tiered support, monitoring, fidelity, and coordinated teams across domains.'], ['Is a tier a student label?', 'No. It describes the intensity of support currently being provided.'], ['What makes screening actionable?', 'Valid decisions, equitable participation, clear rules, follow-up capacity, and monitored classification errors.'], ['What supports implementation at scale?', 'Leadership, training, coaching, resources, time, data systems, feedback, and contextual adaptation.'], ['What if averages improve but a gap widens?', 'Report both, examine system decision points and access, engage affected groups, and revise.']]),

  chapter('sp5403-ch-08', 'safe-supportive-schools', 'Safe and Supportive Schools and Crisis Systems',
    'Build preventive school-climate, behavior, bullying, threat, suicide, and crisis systems that are coordinated, equitable, accessible, and continuously evaluated.',
    ['Assess climate and implement preventive behavior supports.', 'Distinguish bullying from balanced conflict.', 'Design threat, suicide, crisis, and recovery systems.'], [
      section('Climate and universal prevention', 'School climate includes safety, belonging, relationships, teaching and learning conditions, fairness, physical environment, and participation. Combine confidential perception data from students, families, and staff with attendance, discipline, achievement, referral, observation, and qualitative evidence. Universal positive behavior support defines and teaches expectations, improves routines, acknowledges appropriate behavior, responds consistently and instructionally, and uses disaggregated data. Lack of reports is not proof of safety.', ['school climate', 'universal prevention', 'PBIS']),
      section('Bullying and violence prevention', 'Bullying involves repeated or likely repeated aggression and a power imbalance, so peer mediation and equal compromise may endanger or blame the targeted student. Use immediate protection, authorized investigation, accountability, support, family communication, climate and bystander work, and monitoring under current policy. Violence prevention also strengthens connection, reporting pathways, conflict skills, supportive adults, equitable discipline, and timely access to mental-health services.', ['bullying', 'power imbalance', 'bystander']),
      section('Threat and suicide assessment systems', 'Behavioral threat assessment uses a trained multidisciplinary process to investigate communication, context, intent, planning, capability, stressors, targets, access, protective factors, and supports; it does not profile or predict from one score. Suicide systems combine promotion, prevention, gatekeeper training, identification, safe referral, trained risk assessment, caregiver and community coordination, means safety within role, emergency procedures, postvention, and outcome review. Screening without response capacity is unsafe.', ['threat assessment', 'suicide prevention', 'protective factor']),
      section('Crisis preparedness, response, and recovery', 'A comprehensive plan covers prevention and mitigation, incident roles, communication, physical safety, accessibility, family reunification, psychological triage, continuity, responder support, training and exercises, recovery, and after-action improvement. During an event, use verified information and assigned command roles. Recovery continues over time and monitors functioning, access, new risk, service use, equity, family and staff feedback, implementation, and the need to revise supports and plans.', ['crisis plan', 'reunification', 'recovery']),
    ], [['What is school climate?', 'Perceptions and conditions involving safety, belonging, relationships, learning, fairness, environment, and participation.'], ['What is a PBIS foundation?', 'Define and teach expectations, reinforce them, respond instructionally, and use data to improve systems.'], ['Why not mediate bullying?', 'A power imbalance undermines safe voluntary negotiation and calls for protection and accountability.'], ['What is threat assessment?', 'A structured multidisciplinary investigation of facts, context, capability, intent, needs, and management.'], ['What makes suicide prevention comprehensive?', 'Promotion, identification, trained response, referral, caregiver/community coordination, postvention, and evaluation.'], ['What follows crisis response?', 'Longitudinal recovery, service coordination, monitoring, stakeholder feedback, and after-action plan revision.']]),

  chapter('sp5403-ch-09', 'family-school-community', 'Family, School, and Community Collaboration',
    'Create reciprocal, culturally responsive family partnerships and coordinated community services that center strengths, access, consent, student voice, and shared outcomes.',
    ['Apply family-systems and strengths perspectives.', 'Remove barriers to meaningful family participation.', 'Coordinate home, wraparound, and transition supports.'], [
      section('Family systems and reciprocal expertise', 'Families contribute history, culture, language, routines, relationships, priorities, strengths, and evidence outside school. Family-systems thinking examines reciprocal roles, boundaries, communication, stress, resources, and transitions rather than assigning the child or caregiver sole blame. Ask what the family wants to change, what already works, and what burden a plan creates. Participation means family evidence can influence the decision, not merely that a caregiver attended a meeting.', ['family systems', 'family strength', 'reciprocal partnership']),
      section('Access and trustworthy engagement', 'Low participation may reflect work schedules, transportation, disability access, childcare, language, prior harm, technology, immigration concerns, or meetings that offer no meaningful role. Ask families directly about preferred communication, time, format, and contribution; vary options; provide qualified interpretation and translated material; and report how input shaped action. Do not use students as interpreters for sensitive decisions or treat one liaison as representative of every family.', ['family engagement', 'qualified interpreter', 'access barrier']),
      section('Home intervention that fits', 'Co-design a small strategy embedded in an authentic routine. Define the target and family-valued goal, model the procedure, identify feasible prompts and reinforcement, minimize materials and time, agree on simple outcome evidence, and schedule review. Preserve cultural values and caregiver authority. A complex school protocol copied into the home may be technically sound but unusable; acceptability, burden, and consistency are part of intervention quality.', ['home intervention', 'caregiver coaching', 'acceptability']),
      section('Wraparound and transition coordination', 'Complex needs may require a family-driven team with shared strengths-based outcomes, student voice, defined agency and school roles, consent and information boundaries, coordinated actions, crisis and continuity plans, and regular review. For postsecondary transition, begin early, center self-determination and measurable goals, invite agencies with required consent, address eligibility and access, and confirm connections. Another agency’s involvement does not automatically end school responsibilities.', ['wraparound', 'interagency collaboration', 'transition']),
    ], [['What does family-systems thinking prevent?', 'Blaming one member while ignoring reciprocal relationships, routines, culture, stressors, and strengths.'], ['What makes family participation meaningful?', 'Accessible communication and a genuine opportunity for family evidence and priorities to shape decisions.'], ['Who should interpret sensitive meetings?', 'A qualified interpreter who protects accuracy, neutrality, and confidentiality.'], ['What makes a home intervention feasible?', 'Fit with family goals, culture, routine, time, materials, burden, and simple review data.'], ['What defines wraparound?', 'Family-driven strengths-based coordination across roles and agencies around shared outcomes.'], ['What anchors transition planning?', 'Student goals and self-determination, early coordination, consent, clear roles, access, and follow-through.']]),

  chapter('sp5403-ch-10', 'equitable-diverse-practice', 'Equitable and Culturally Responsive Practice',
    'Examine identity, language, disability, opportunity, bias, power, access, and system decision points to promote fair assessment, intervention, and outcomes.',
    ['Integrate culture without stereotyping.', 'Identify and interrupt implicit and systemic bias.', 'Evaluate disproportionality, access, and resource equity.'], [
      section('Culture and identity are evidence, not destiny', 'Age, development, race, ethnicity, language, nationality, religion, gender identity, sexual orientation, disability, health, socioeconomic conditions, migration, and community context can shape experience and access. Ask how these factors matter for this student rather than applying group averages as traits. Use cultural humility: reflect on one’s limits, invite correction, seek community knowledge, and remain accountable. Culture-blind practice can hide construct barriers and unequal opportunity.', ['cultural humility', 'identity', 'within-group variation']),
      section('Bias at individual and system levels', 'Implicit and explicit bias can affect which behavior is noticed, how it is described, who is referred, which tests are selected, how ambiguity is interpreted, and what placement follows. Operationalize criteria, use multiple sources, check decision consistency, examine disaggregated rates at each step, involve affected communities, and create accountability. Good intentions do not substitute for process evidence and outcome monitoring.', ['implicit bias', 'decision point', 'accountability']),
      section('Language, disability, and construct access', 'For multilingual learners, examine proficiency in relevant languages, instruction and opportunity, mobility, family history, culturally responsive intervention response, and appropriate assessment form. Qualified interpreters need briefing, role clarity, and debriefing. For disability-related sensory, motor, communication, or health barriers, preserve the intended construct while changing irrelevant response demands and documenting standardization and interpretive limits.', ['multilingual learner', 'construct access', 'interpreter']),
      section('Disproportionality and equitable systems', 'Analyze disproportionality across referral, screening, discipline, evaluation, eligibility, placement, course access, and service intensity rather than only final counts. A disparity is a signal for inquiry, not proof about each case. Correct system barriers without withholding individualized evaluation or support. Equity allocates responsive resources to address need and access barriers; evaluate reach, opportunity cost, burden, benefit, and unintended effects, not just equal invitation or distribution.', ['disproportionality', 'equity', 'reach']),
    ], [['What is cultural humility?', 'Ongoing self-reflection, openness to correction, attention to power, community learning, and accountability.'], ['Why is culture-blind practice risky?', 'It can hide language, opportunity, identity, power, and access factors relevant to valid decisions.'], ['How can bias be interrupted?', 'Operational criteria, multiple sources, disaggregated decision data, affected voices, consultation, and accountability.'], ['What protects multilingual evaluation?', 'Language proficiency and opportunity evidence, appropriate methods, qualified interpreters, and multiple sources.'], ['What does disproportionality require?', 'Analysis of decision points and systems while preserving individualized evaluation and support.'], ['Equality versus equity?', 'Equality provides the same; equity responds to need and barriers to promote fair access and opportunity.']]),

  chapter('sp5403-ch-11', 'research-program-evaluation', 'Research, Evidence-Based Practice, and Program Evaluation',
    'Evaluate research design and statistics, integrate evidence with context, and conduct decision-focused program evaluation with implementation and equity data.',
    ['Distinguish experimental, quasi-experimental, single-case, and mixed methods.', 'Interpret validity threats, effect size, and uncertainty.', 'Design useful program and implementation evaluations.'], [
      section('Design answers a claim', 'Randomized experiments strengthen causal inference through random assignment but still require valid measures, fidelity, attrition analysis, and ethical implementation. Quasi-experiments use comparison groups, interrupted time series, matching, or other structures without random assignment and must address selection. Single-case designs use repeated measurement and replicated phase changes across time, behaviors, people, or settings. Descriptive and qualitative designs can answer prevalence, experience, process, and context questions without pretending to prove causality.', ['random assignment', 'quasi-experiment', 'single-case design']),
      section('Validity threats and statistical interpretation', 'History, maturation, testing, instrumentation, regression, selection, attrition, and contamination offer alternative explanations for change. Statistical significance reflects evidence under a model, not effect magnitude, importance, or replication. Examine effect size, confidence interval, baseline risk, measure quality, practical benefit, adverse effects, subgroup response, and cost. Correlation does not establish cause; multiple analyses and small samples require additional caution.', ['internal validity', 'effect size', 'confidence interval']),
      section('Evidence-based practice is an integration', 'Evaluate peer review, design fit, comparison, measurement, implementation, analysis, transparency, replication, population, and setting. Then integrate the best available research with student or system data, professional expertise, stakeholder values, culture, feasibility, and resources. Evidence-based does not mean a brand is universally effective. Define the expected mechanism and outcome, monitor implementation and response locally, and change course when evidence contradicts the plan.', ['research quality', 'external validity', 'evidence-based practice']),
      section('Program evaluation and implementation', 'Decision-focused evaluation states users and decisions, need and theory of change, population and reach, implementation, outcomes, equity, cost or burden, stakeholder experience, limitations, and recommendations. Implementation evidence includes adherence, dosage, quality, responsiveness, adaptations, training, coaching, leadership, and context. Mixed methods can explain how and for whom quantitative outcomes occurred. Protect privacy and report unfavorable findings with the same honesty as favorable ones.', ['program evaluation', 'theory of change', 'implementation fidelity']),
    ], [['What does random assignment address?', 'Preexisting selection differences between conditions, strengthening causal inference.'], ['What is a quasi-experiment?', 'A design using comparison or time structure without random assignment.'], ['How does single-case design show control?', 'Repeated outcome changes systematically associated with replicated intervention phase changes.'], ['Why is significance insufficient?', 'It does not establish effect magnitude, precision, practical value, validity, equity, or feasibility.'], ['What is evidence-based practice?', 'Integration of research, local data, expertise, stakeholder values, culture, context, and monitoring.'], ['What belongs in program evaluation?', 'Need, theory, reach, implementation, outcomes, equity, cost, experience, limitations, and decision recommendations.']]),

  chapter('sp5403-ch-12', 'legal-ethical-professional', 'Legal, Ethical, and Professional Practice',
    'Apply NASP ethical problem solving, IDEA and Section 504 principles, FERPA privacy, consent, competence, reporting, documentation, and current jurisdiction-specific rules.',
    ['Protect informed participation and education records.', 'Apply evaluation and disability-rights procedures.', 'Use competence, supervision, and structured ethical decision making.'], [
      section('Consent, assent, privacy, and records', 'Explain services, foreseeable risks and benefits, participation, records, and privacy limits in language the student and caregiver can understand. Follow current requirements for parent consent and student assent or self-determination. FERPA controls access and disclosure of education records; employment in the school does not create unlimited access. Verify legitimate educational interest, consent, and exceptions, disclose only authorized necessary information, use secure systems, and document the basis and recipients.', ['informed consent', 'assent', 'FERPA']),
      section('IDEA and comprehensive evaluation', 'Before initial evaluation, provide required notice and obtain informed parent consent; consent to evaluate is not consent for initial services. IDEA evaluation uses varied technically sound tools and strategies, includes parent information, addresses all suspected need areas, uses appropriate language and access, and never makes one measure the sole criterion. Teams determine eligibility and educational need. Parents who disagree with an agency evaluation have specific independent educational evaluation rights that must be handled without unnecessary delay.', ['IDEA evaluation', 'parent consent', 'independent educational evaluation']),
      section('Section 504, access, and professional competence', 'Section 504 prohibits disability discrimination in covered schools and can require individualized aids and services even without IDEA eligibility. A diagnosis does not automatically prescribe a standard plan. School psychologists contribute evidence within lawful team processes rather than deciding alone. Provide only services for which education, training, supervised experience, consultation, and credentials support competence; obtain supervision or refer when a method, population, or problem exceeds current limits.', ['Section 504', 'individualized access', 'competence']),
      section('Ethical problem solving and protection duties', 'Define the dilemma, stakeholders, rights, power, culture, development, risks, and conflicts. Review current NASP ethics, federal and state law, credential rules, and district policy; consult without unnecessary disclosure; generate options; compare consequences; act, document, and evaluate. For suspected maltreatment, imminent harm, or other protection duties, follow current jurisdictional reporting and crisis procedures promptly, do not promise secrecy, and do not conduct an unauthorized investigation.', ['ethical problem solving', 'mandated reporting', 'documentation']),
    ], [['What is informed consent?', 'Understandable voluntary authorization after disclosure of purpose, procedures, risks, benefits, privacy, and alternatives.'], ['Does school employment permit all record access?', 'No. FERPA, consent, legitimate educational interest, exceptions, and minimum necessary disclosure govern.'], ['What does IDEA prohibit in evaluation?', 'Using a single measure as the sole criterion for eligibility or programming.'], ['What happens after an IEE request at public expense?', 'The agency generally provides it or files due process without unnecessary delay, subject to governing criteria.'], ['What is competence?', 'Practice supported by appropriate education, training, supervised experience, consultation, and credentials.'], ['What anchors ethical decisions?', 'Ethics, current law and policy, culture and power, consultation, consequences, documentation, and follow-up.']]),
];

const memoryAids = [
  { title: 'RIOT Before a Routine Battery', content: 'Review records, Interview, Observe, and Test or otherwise directly measure only what answers the referral question. Multiple relevant methods beat automatic test batteries.', tags: ['assessment', 'RIOT'], references: [S.ETS, S.NASP_STANDARDS] },
  { title: 'Problem Solving: Define, Analyze, Act, Evaluate', content: 'Operationalize the gap, test alterable hypotheses, implement a matched strategy, and evaluate outcome plus fidelity using an advance decision rule.', tags: ['problem solving', 'data'], references: [S.ETS, S.NASP_DOMAINS] },
  { title: 'Score Range, Not Score Point', content: 'Use reliability, standard error, confidence intervals, norm relevance, and context. One obtained score is not a perfectly precise trait value.', tags: ['measurement', 'reliability'], references: [S.ETS] },
  { title: 'Reliable Does Not Mean Valid for This Use', content: 'Consistency is necessary but not sufficient. Ask whether evidence supports the exact construct interpretation and decision for this student and context.', tags: ['validity', 'measurement'], references: [S.ETS, S.NASP_STANDARDS] },
  { title: 'Consultation: Relationship, Problem, Plan, Review', content: 'Build trust, define the shared measurable concern, create a feasible role-clear plan, then review fidelity, outcomes, acceptability, and next action.', tags: ['consultation', 'collaboration'], references: [S.ETS, S.NASP_DOMAINS] },
  { title: 'Instruction: Model, Guide, Feedback, Release', content: 'Explicitly model the target, guide many responses, give immediate feedback and review, then release independence only when learner data show readiness.', tags: ['instruction', 'academic'], references: [S.ETS] },
  { title: 'Access Preserves the Construct', content: 'An accommodation removes a barrier unrelated to the goal. A modification changes content or expected performance. Document any effect on interpretation.', tags: ['accommodation', 'access'], references: [S.ETS, S.IDEA_EVAL] },
  { title: 'Tiers Describe Support, Not Students', content: 'Tier 1 is universal, Tier 2 targeted, and Tier 3 intensive. Students move among support intensities based on need and response; tiers are not identities.', tags: ['MTSS', 'prevention'], references: [S.ETS, S.NASP_STANDARDS] },
  { title: 'FBA: Context, Antecedent, Behavior, Consequence, Function', content: 'Define the response, compare occurrences and nonoccurrences, build a testable function, then prevent, teach, and reinforce a matched replacement response.', tags: ['FBA', 'behavior'], references: [S.ETS] },
  { title: 'Safety First, No Secrecy Promise', content: 'For imminent harm, maintain supervision and activate current crisis procedures. For suspected abuse, follow current reporting law without investigating independently.', tags: ['safety', 'ethics'], references: [S.NASP_ETHICS, S.ETS] },
  { title: 'MTSS Integrates, It Does Not Delay', content: 'Coordinate academic, behavior, and mental-health screening and supports through common problem solving; never use intervention tiers to delay a required evaluation.', tags: ['MTSS', 'IDEA'], references: [S.NASP_STANDARDS, S.IDEA] },
  { title: 'Climate Needs Perception and Outcome Data', content: 'Combine student, family, and staff voice with attendance, discipline, learning, referral, observation, and subgroup evidence. Silence is not proof of safety.', tags: ['school climate', 'systems'], references: [S.ETS, S.NASP_STANDARDS] },
  { title: 'Bullying Is Not Balanced Conflict', content: 'Power imbalance makes equal compromise unsafe. Protect, investigate through authorized channels, support, hold accountable, prevent systemically, and monitor.', tags: ['bullying', 'safety'], references: [S.ETS] },
  { title: 'Threat Assessment Is Facts, Not Profiles', content: 'Use a trained multidisciplinary process to investigate context, intent, capability, stressors, protective factors, needs, management, and follow-up.', tags: ['threat assessment', 'crisis'], references: [S.ETS, S.NASP_STANDARDS] },
  { title: 'Family Partnership: Access Plus Influence', content: 'Remove schedule, language, disability, technology, trust, and transportation barriers, then ensure family evidence and priorities can actually shape decisions.', tags: ['family', 'collaboration'], references: [S.ETS, S.NASP_DOMAINS] },
  { title: 'Bias Audit the Decision Path', content: 'Examine operational definitions and disaggregated rates at referral, discipline, screening, testing, eligibility, placement, and service access—not final counts alone.', tags: ['equity', 'bias'], references: [S.NASP_STANDARDS, S.IDEA_EVAL] },
  { title: 'Research: Claim Sets the Design', content: 'Causal, descriptive, predictive, experience, and implementation questions need different designs. Match methods to the claim and state alternative explanations.', tags: ['research', 'design'], references: [S.ETS] },
  { title: 'Significant Is Not Necessarily Important', content: 'After a p value, inspect effect size, confidence interval, practical benefit, cost, adverse effects, subgroup response, validity, and replication.', tags: ['statistics', 'effect size'], references: [S.ETS] },
  { title: 'IDEA Evaluation: Multiple, Relevant, Accessible, Comprehensive', content: 'Use varied technically sound sources, appropriate language and access, all suspected areas, parent evidence, and no single sole criterion.', tags: ['IDEA', 'evaluation'], references: [S.IDEA_EVAL, S.ETS] },
  { title: 'Ethics: Define, Standards, Consult, Options, Act, Review', content: 'Name the dilemma and power, review current ethics and law, consult appropriately, compare consequences, document action, and evaluate the result.', tags: ['ethics', 'professional practice'], references: [S.NASP_ETHICS, S.NASP_STANDARDS] },
];

